import{_ as e,o as l,c as a,ag as n}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Inhaltsverzeichnis","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/inhaltsverzeichnis.md","filePath":"lektionen/inhaltsverzeichnis.md"}'),t={name:"lektionen/inhaltsverzeichnis.md"};function r(s,i,u,o,h,k){return l(),a("div",null,[...i[0]||(i[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="inhaltsverzeichnis" tabindex="-1">Inhaltsverzeichnis <a class="header-anchor" href="#inhaltsverzeichnis" aria-label="Permalink to &quot;Inhaltsverzeichnis&quot;">​</a></h1><h2 id="lektion-1" tabindex="-1"><a href="./lektion01">Lektion 1</a> <a class="header-anchor" href="#lektion-1" aria-label="Permalink to &quot;[Lektion 1](lektion01)&quot;">​</a></h2><ul><li>गणेशपूजनम् = gaṇeśapūjanam = Verehrung des Gaṇeśa</li><li>मङ्गलचरणम् = maṅgalacaraṇam = &quot;Glückbringender Anfang&quot;</li><li>1. Literatur für Anfänger in Indologie</li><li>2. Die Laute des Sanskrit nach der traditionellen indischen Klassifikation und ihre wissenschaftliche Umschrift <ul><li>2.1. Zur Aussprache einzelner Laute</li></ul></li><li>3. Übung</li></ul><h2 id="lektion-2" tabindex="-1"><a href="./lektion02">Lektion 2</a> <a class="header-anchor" href="#lektion-2" aria-label="Permalink to &quot;[Lektion 2](lektion02)&quot;">​</a></h2><ul><li>1. Der Nominalsatz</li><li>2. Zur Deklination (Beugung von Nomina)</li><li>3. Der Nominativ Singular = prathamā ekavacanam = प्रथमा एकवचनम् <ul><li>3.1. Nominativ Singular auf -s</li></ul></li><li>4. Sandhi -- सन्धि <ul><li>4.1. Sandhi von auslautendem -s</li></ul></li><li>5. Wortliste</li><li>6. Übung</li></ul><h2 id="lektion-3" tabindex="-1"><a href="./lektion03">Lektion 3</a> <a class="header-anchor" href="#lektion-3" aria-label="Permalink to &quot;[Lektion 3](lektion03)&quot;">​</a></h2><ul><li>1. Nominativ singular = prathamā ekavacanam = प्रथमा एकवचनम् (Fortsetzung) <ul><li>1.1. Nominativ Singular auf -s (Fortsetzung)</li><li>1.2. Nominativ singular ohne Endung</li></ul></li><li>2. Bildung der Feminina zu Maskulina (Adjektive und Substantive)</li><li>3. Nominativ plural = prathamā bahuvacanam = प्रथमा बहुचनम्</li><li>4. Vokalsandhi</li><li>5. Satzsandhi von -ās</li><li>6. Wortliste</li><li>7. Übung</li></ul><h2 id="lektion-4" tabindex="-1"><a href="./lektion04">Lektion 4</a> <a class="header-anchor" href="#lektion-4" aria-label="Permalink to &quot;[Lektion 4](lektion04)&quot;">​</a></h2><p>Gesprochenes Sanskrit</p><ul><li>1. Einfache Ergänzungsfragen (Wortfragen) und Antworten <ul><li>1.1. Fragepronomina (praśnārthakasarvanāma n.) und Demonstrativpronomina (nidarśakasarvanāma n.) = प्रश्नार्थकसर्वनाम निदर्शकसर्वनामानि च <ul><li>1.1.1.Fragepronomen (praśnārthakasarvanāma n. = प्रश्नार्थकसर्वनामन्)</li><li>1.1.2. Demonstrativponomina (nidarśakasarvanāmāni n. = निदर्शकसर्वनामानि)</li></ul></li><li>1.2. Sandhi von auslautendem -m</li><li>1.3. Sandhi von auslautendem -e</li><li>1.4. Sandhi von aulautendem -d</li><li>1.5. Frageformeln</li></ul></li><li>2. Übung</li></ul><h2 id="lektion-5" tabindex="-1"><a href="./lektion05">Lektion 5</a> <a class="header-anchor" href="#lektion-5" aria-label="Permalink to &quot;[Lektion 5](lektion05)&quot;">​</a></h2><ul><li>1. Nominalkomposita = samāsa m. = समास</li><li>2. Zur Sanskrit-Terminologie für Komposita</li><li>3. Kopulative Komposita = Dvandva n. (&quot;Paar&quot;) = द्वन्द्व <ul><li>3.1. Vorderglieder von Komposita</li><li>3.2. Plural-Itaretaradvandva</li></ul></li><li>4. Wortliste</li><li>5. Übung</li></ul><h2 id="lektion-6" tabindex="-1"><a href="./lektion06">Lektion 6</a> <a class="header-anchor" href="#lektion-6" aria-label="Permalink to &quot;[Lektion 6](lektion06)&quot;">​</a></h2><ul><li>1. Der Verbalsatz</li><li>2. Zur Bildung der Verbalformen</li><li>3. Indikativ Präsens (laṭ = लट्)</li><li>4. Primärendungen der dritten Person (prathama m. = प्रथम = &quot;erste (!) Person&quot;)</li><li>5. Bildung des Präsensstamms <ul><li>5.1. Verben der 6. Präsensklasse (tudādi = तुदादि = &quot;tud usw.&quot;)</li><li>5.2. Verben der 1. Präsensklasse (bhvādi / bhūvādi = भ्वादि / भूवादि = &quot;bhū usw.&quot;) <ul><li>5.2.1. Wortsandhi von e und o</li><li>5.2.2. Lautabstufung (Ablaut)</li></ul></li><li>5.3. Verben der 4. Präsensklasse (divādi = दिवादि = &quot;div usw.&quot;)</li><li>5.4. Themavokal, thematische Präsensklassen</li></ul></li><li>6. Gesprochenes Sanskrit: Weitere Fragen (praśna m. = प्रश्न)</li><li>7. Wortliste</li><li>8. Übung</li><li>9. Wiederholungsübung</li></ul><h2 id="lektion-7" tabindex="-1"><a href="./lektion07">Lektion 7</a> <a class="header-anchor" href="#lektion-7" aria-label="Permalink to &quot;[Lektion 7](lektion07)&quot;">​</a></h2><p>Wochenspruch</p><ul><li>1. Der Verbalsatz mit direktem Objekt</li><li>2. Der Akkusativ (Wenfall, dvitīyā f. = द्वितीया = &quot;zweite Kasusendung&quot;) <ul><li>2.1. Akkusativ singular und Plural der Frage- und Demonstrativpronomina</li><li>2.2. Gebrauch des Akkusativ (Wenfall, dvitīyā f. = द्वितीया = &quot;zweite Kasusendung&quot;)</li></ul></li><li>3. Sandhi von auslautendem -n</li><li>4. Das Neutrum (napuṃsaka n. =  नपुंसक) <ul><li>4.1. Neutrum der Stämme auf -a</li></ul></li><li>5. Athematische Präsensklassen <ul><li>5.1. Primärendungen der 3. Person Plural bei athematischen Präsensstämmen</li><li>5.2. Die 5. Präsensklasse (svādi = स्वादि = &quot;su usw.&quot;</li></ul></li><li>6. Wortliste</li><li>7. Übung</li></ul><h2 id="lektion-8" tabindex="-1"><a href="./lektion08">Lektion 8</a> <a class="header-anchor" href="#lektion-8" aria-label="Permalink to &quot;[Lektion 8](lektion08)&quot;">​</a></h2><ul><li>1. Zur Bildung von Nomina</li><li>2. Einteilung der Nominalsuffixe</li><li>3. Einige wichtige Nominalsuffixe <ul><li>3.1. -a m. (kṛt)</li><li>3.2. -ana n. (kṛt)</li><li>3.3. -tra n. (kṛt)</li><li>3.4. -ti f. (kṛt)</li><li>3.5. -tva n., tā f. (taddhita)</li></ul></li><li>4. Die 8. Präsensklasse (tanādi = तनादि = &quot;tan usw.&quot;)</li><li>5. Wortliste</li><li>6. Übung</li><li>7. Lese- und Übersetzungsübung</li></ul><h2 id="lektion-9" tabindex="-1"><a href="./lektion09">Lektion 9</a> <a class="header-anchor" href="#lektion-9" aria-label="Permalink to &quot;[Lektion 9](lektion09)&quot;">​</a></h2><ul><li>1. Samāhāradvandva = सआहारद्वन्द्व (&quot;Zusammenfassungsdvandva&quot;)</li><li>2. Zur Bildung von Nominalstämmen <ul><li>2.1. -ka (taddhita)</li><li>2.2. -aka (kṛt), fem. oft -ikā</li></ul></li><li>3. Wortliste</li><li>4. Übung</li></ul><h2 id="lektion-10" tabindex="-1"><a href="./lektion10">Lektion 10</a> <a class="header-anchor" href="#lektion-10" aria-label="Permalink to &quot;[Lektion 10](lektion10)&quot;">​</a></h2><ul><li>1. Der Passivsatz</li><li>2. Der Instrumentalis = tṛtīyā f. = तृतीया = &quot;dritte Kasusendung&quot; <ul><li>2.1. Zum Gebrauch des Instrumentalis (tṛtīyā = तृतीया)</li></ul></li><li>3. Das sogenannte Cerebralisationsgesetz für -n- (ein Wortsandhi)</li><li>4. Das Passiv, Indikativ Präsens (yak = यक्) <ul><li>4.1. Sonderregeln zur Bildung des Passiv</li></ul></li><li>5. Wortliste</li><li>6. Übung</li><li>7. Wortliste 2</li><li>8. Lese- und Übersetzungsübung</li></ul><h2 id="lektion-11" tabindex="-1"><a href="./lektion11">Lektion 11</a> <a class="header-anchor" href="#lektion-11" aria-label="Permalink to &quot;[Lektion 11](lektion11)&quot;">​</a></h2><ul><li>1. Doppelter Akkusativ</li><li>2. Wortliste</li><li>3. Übung</li><li>4. Wiederholungsübung</li></ul><h2 id="lektion-12" tabindex="-1"><a href="./lektion12">Lektion 12</a> <a class="header-anchor" href="#lektion-12" aria-label="Permalink to &quot;[Lektion 12](lektion12)&quot;">​</a></h2><ul><li>1. Partizip Perfekt Passiv (PPP) <ul><li>1.1. Schema für transitive Verben</li><li>1.2. Schema I für intransitive Verben und Verben der der Bewegung</li><li>1.3. Schema II für intransitive Verben und Verben der Bewegung</li></ul></li><li>2. Zur Bedeutung des PPP</li><li>3. Bildung des PPP <ul><li>3.1. PPP auf -ta (kta) <ul><li>3.1.1. Ohne Bindevokal -i- (aniṭ)</li><li>3.1.2. Mit Bindevokal -i- (seṭ)</li></ul></li></ul></li><li>4. Gesetze der Lautverbindung im Wort</li><li>5. Wortliste <ul><li>5.1. Passiv und PPP der bisher gelernten Wurzeln</li></ul></li><li>6. Übung</li></ul><h2 id="lektion-13" tabindex="-1"><a href="./lektion13">Lektion 13</a> <a class="header-anchor" href="#lektion-13" aria-label="Permalink to &quot;[Lektion 13](lektion13)&quot;">​</a></h2><ul><li>1. PPP auf -na-</li><li>2. Weiteres zum Gebrauch des PPP</li><li>3. Attributive Bestimmungen von Nomina (Wortstellung)</li><li>4. Bildung von Adjektiven auf -mant und -vant (taddhita)</li><li>5. Stammabstufung von Nomina</li><li>6. Zum Wortsandhi</li><li>7. Kasusendungen konsonantischer Stämme</li><li>8. Deklination der Stämme auf -mant und -vant</li><li>9. Wortliste</li><li>10. Übung</li><li>11. Wiederholungsübung</li></ul><h2 id="lektion-14" tabindex="-1"><a href="./lektion14">Lektion 14</a> <a class="header-anchor" href="#lektion-14" aria-label="Permalink to &quot;[Lektion 14](lektion14)&quot;">​</a></h2><ul><li>1. Der Ausdruck des Verhältnisses von durch Substantive Bezeichnetem: der Genetiv (ṣaṣṭhī f. = षष्टी = sechste Kasusendung)</li><li>2. Bildung der Genetivformen (ṣāṣṭhī f. = षष्ठी)</li><li>3. Weiteres zum Gebrauch des Genetiv (षष्ठी)</li><li>4. Wortliste</li><li>5. Subhāṣitāni = सुभाषितानि = Sprichwörter</li><li>6. Übung</li></ul><h2 id="lektion-15" tabindex="-1"><a href="./lektion15">Lektion 15</a> <a class="header-anchor" href="#lektion-15" aria-label="Permalink to &quot;[Lektion 15](lektion15)&quot;">​</a></h2><ul><li>१. सुभाषितम्</li><li>2. Determinativkomposita = Tatpuruṣa m. = तत्पुरुष</li><li>3. Determinativkomposita mit attributivem / appositionellem Vorderglied = Karmadhāraya m. = कर्मधारय</li><li>4. Determinativkomposita mit einem Vorderglied, das zum Hinterglied in einem nicht-attributiv/appositionellem Kasusverhältnis steht = Tatpuruṣa im engeren Sinn</li><li>5. Zerlegung von Komposita (außer Dvandvas)</li><li>6. Die Form des Vorderglieds in Komposita (समास m.)</li><li>7. Einteilung der तत्पुरुष <ul><li>7.1. Einteilung der कर्मधारय</li></ul></li><li>8. Wortliste</li><li>9. Übung 1</li><li>10. Übung 2</li><li>11. Übung 3</li></ul><h2 id="lektion-16" tabindex="-1"><a href="./lektion16">Lektion 16</a> <a class="header-anchor" href="#lektion-16" aria-label="Permalink to &quot;[Lektion 16](lektion16)&quot;">​</a></h2><ul><li>1. Zum Sandhi auslautender Konsonanten</li><li>2. Wortliste</li><li>3. Übung</li><li>4. Wiederholungsübung</li></ul><h2 id="lektion-17" tabindex="-1"><a href="./lektion17">Lektion 17</a> <a class="header-anchor" href="#lektion-17" aria-label="Permalink to &quot;[Lektion 17](lektion17)&quot;">​</a></h2><ul><li>1. Zweite Präsensklasse (अदादि = अद् usw.)</li><li>2. Wurzeln der zweiten Präsensklasse mit Stammabstufung Hochstufe - Tiefstufe</li><li>3. Wurzeln der zweiten Präsensklasse mit Stammabstufung Dehnstufe - Tiefstufe</li><li>4. Wurzeln der zweiten Präsensklasse ohne Stammabstufung</li><li>5. Zweisilbige Wurzeln auf -i/-ī mit Stammabstufung</li><li>6. Wortliste</li><li>7. Übung 1</li><li>8. Übung 2</li></ul><h2 id="lektion-18" tabindex="-1"><a href="./lektion18">Lektion 18</a> <a class="header-anchor" href="#lektion-18" aria-label="Permalink to &quot;[Lektion 18](lektion18)&quot;">​</a></h2><ul><li>१. सुभाषितम्</li><li>2. Determinativkomposita (तत्पुरुष) mit adverbialem Vorderglied <ul><li>2.1. Komposita vom Typ सुकर / दुष्कर</li><li>2.2. Bedeutungen von nañ-Tatpuruṣa (a- / an-)</li></ul></li><li>3. Verbalkomposita <ul><li>3.1. Nominalbildungen zu Verbalkomposita</li></ul></li><li>4. Wortliste</li><li>5. Übung</li><li>6. Wiederholungsübung</li></ul><h2 id="lektion-19" tabindex="-1"><a href="./lektion19">Lektion 19</a> <a class="header-anchor" href="#lektion-19" aria-label="Permalink to &quot;[Lektion 19](lektion19)&quot;">​</a></h2><ul><li>1. Der Relativsatz</li><li>2. Das Relativpronomen = व्यपेक्षकसर्वनाम n.</li><li>3. Wortliste</li><li>4. Übung</li><li>५. सुभाषितानि</li></ul><h2 id="lektion-20" tabindex="-1"><a href="./lektion20">Lektion 20</a> <a class="header-anchor" href="#lektion-20" aria-label="Permalink to &quot;[Lektion 20](lektion20)&quot;">​</a></h2><ul><li>1. Possesivkomposita = बहुव्रीहि m.</li><li>2. Bahuvrīhi mit attributivem Vorderglied</li><li>3. Bahuvrīhi mit appositionellem Vorderglied</li><li>4. Bahuvrīhi mit kasuellem Vorderglied</li><li>5. Bahuvrīhi mit adverbiellem Vorderglied</li><li>6. Flexion des Schlussglieds eines Bahuvrīhi</li><li>7. Eine andere Einteilung der Arten von Bahuvrīhis</li><li>8. Verhältnis von Bahuvrīhi und Relativsatz</li><li>9. Wortliste</li><li>10. Übung 1</li><li>11. Übung 2</li><li>12. Übersetzungsübung</li></ul><h2 id="lektion-21" tabindex="-1"><a href="./lektion21">Lektion 21</a> <a class="header-anchor" href="#lektion-21" aria-label="Permalink to &quot;[Lektion 21](lektion21)&quot;">​</a></h2><ul><li>1. Weitere Präsensstämme auf -nt <ul><li>1.1. Partizip Präsens (लडादेशः) Parasmaipada</li><li>1.2. महान्त् &quot;groß&quot;</li></ul></li><li>2. Sandhi für auslautende Nasale</li><li>3. Höfliche Formen der Anrede</li><li>4. Wortliste</li><li>5. Übung</li></ul><h2 id="lektion-22" tabindex="-1"><a href="./lektion22">Lektion 22</a> <a class="header-anchor" href="#lektion-22" aria-label="Permalink to &quot;[Lektion 22](lektion22)&quot;">​</a></h2><ul><li>1. Das Absolutivum (क्त्वा । ल्यप्)</li><li>2. Bildung des Absolutivums <ul><li>2.1. Verben ohne Präverb: Absolutiv auf -त्वा</li><li>2.2. Verben mit Präverb <ul><li>2.2.1. Wurzeln auf langen Vokal (außer -ā) oder auf Konsonant</li><li>2.2.2. Wurzeln auf -ā</li><li>2.2.3. Wurzeln, die in der Tiefstufe auf kurzes -i, -u, -ṛ auslauten</li><li>2.2.4. Wurzeln auf -am / -an, die in der Tiefstufe auf -a auslauten</li></ul></li></ul></li><li>3. Wortliste</li><li>4. Übung</li></ul><h2 id="lektion-23" tabindex="-1"><a href="./lektion23">Lektion 23</a> <a class="header-anchor" href="#lektion-23" aria-label="Permalink to &quot;[Lektion 23](lektion23)&quot;">​</a></h2><ul><li>1. Der Infinitiv (तुमुन्)</li><li>2. Bildung des Infinitiv (तुमुन्)</li><li>3. Der Infinitiv (तुमुन्) zu den bisher gelernten Wurzeln</li><li>4. Wortliste</li><li>5. Übung</li><li>6. Wiederholungsübung</li></ul><h2 id="lektion-24" tabindex="-1"><a href="./lektion24">Lektion 24</a> <a class="header-anchor" href="#lektion-24" aria-label="Permalink to &quot;[Lektion 24](lektion24)&quot;">​</a></h2><ul><li>1. Der Dativ (चतुर्थी = &quot;vierte Kasusendung&quot;)</li><li>2. Bildung des Dativ (चतुर्थी) <ul><li>2.1. Konsonantische Stämme</li><li>2.2. Fragepronomen</li><li>2.3. Demonstrativpronomina</li><li>2.4. Vokalische Stämme</li></ul></li><li>3. Sandhi von auslautendem -ai und -au</li><li>4. Wortliste</li><li>5. Übung</li><li>6. Weitere Übungen zum Gebrauch des Dativ</li></ul><h2 id="lektion-25" tabindex="-1"><a href="./lektion25">Lektion 25</a> <a class="header-anchor" href="#lektion-25" aria-label="Permalink to &quot;[Lektion 25](lektion25)&quot;">​</a></h2><ul><li>1. Bildung des Ablativ (पञ्चमी = &quot;fünfte Kasusendung&quot;)</li><li>2. Gebrauch des Ablativ (पञ्चमी)</li><li>3. Das Suffix -तस्</li><li>4. Andere Möglichkeiten, Begründungen auszudrücken</li><li>5. Wortliste</li><li>6. Übung</li><li>7. सुभाषितानि</li><li>8. Übersetzungsübung</li></ul><h2 id="lektion-26" tabindex="-1"><a href="./lektion26">Lektion 26</a> <a class="header-anchor" href="#lektion-26" aria-label="Permalink to &quot;[Lektion 26](lektion26)&quot;">​</a></h2><ul><li>1. Cerebralisationsgesetz für -s- im Wortinnern</li><li>2. Cerebralisationsgesetz für Dentale im Wortinnern</li><li>3. Wortsandhi für Palatal, Guttural, ṣ, h + -s</li><li>4. Grassmannsches Hauchdissimilationsgesetz</li><li>5. Wortsandhi für -m, -n vor Zischlaut</li><li>6. Gebrauch des einfachen Futurs (ऌत्, भविष्यन्ती f.)</li><li>7. Bildung des einfachen Futurs (ऌत्, भविष्यन्ती  f.)</li><li>8. Übung</li></ul><h2 id="lektion-27" tabindex="-1"><a href="./lektion27">Lektion 27</a> <a class="header-anchor" href="#lektion-27" aria-label="Permalink to &quot;[Lektion 27](lektion27)&quot;">​</a></h2><ul><li>1. Gebrauch des Lokativ (सप्तमी f. = &quot;siebte Kasusendung)</li><li>2. Bildung des Lokativ (सप्तमी) <ul><li>2.1. Konsonatische Stämme</li><li>2.2. Frage, Demonstrativ- und Relativpronomina</li><li>2.3. Vokalische Stämme</li></ul></li><li>3. Übersicht über die regulären Kasusendungen (विभक्ति) des Singular und Plural</li><li>4. Ein Vers mit allen Deklinationsformen des Singular zu राम</li><li>5. Wortliste</li><li>6. Übung</li><li>7. Deklinationsparadigmen zum Auswendiglernen <ul><li>7.1. Maskulina auf -a: नर</li><li>7.2. Neutra auf -a: फल</li><li>7.3. Feminina auf -ā: क्षत्रिया</li><li>7.4. Maskulina auf -i: अरि</li><li>7.5. Feminina auf -i: मति</li><li>7.6. Maskulina auf -u: गुरु</li><li>7.7. Feminina auf -u: धेनु#</li><li>7.8. Mehrsilbige Feminina auf -ī: देवी</li><li>7.9. Partizip Präsens Parasmaipada auf -ant: सन्त्</li><li>7.10. महान्त्</li><li>7.11. Maskulina und Neutra auf -vant / -mant: गुणवन्त्</li><li>7.12. Demonstrativpronomina: तद् । एतद् । इदम्</li><li>7.13. Relativpronomen: यद्</li><li>7.14. Fragepronomen: किम्</li></ul></li></ul><h2 id="lektion-28" tabindex="-1"><a href="./lektion28">Lektion 28</a> <a class="header-anchor" href="#lektion-28" aria-label="Permalink to &quot;[Lektion 28](lektion28)&quot;">​</a></h2><ul><li>1. Das Kausativum (णि, णिच्, कारित)</li><li>2. Satzkonstruktion mit dem Kausativ (णि, णिच्, कारित)</li><li>3. Bildung des Präsensstamms zum Kausativ (णि, णिच्, कारित)</li><li>4. Bildung des Passivs (यक्)  zum Kausativ</li><li>5. Bildung des Futurs (ऌत्, भविष्यन्ती f.) zum Kausativ</li><li>6. Bildung des PPP (क्त) zum Kausativ</li><li>7. Bildung des Absolutivs (क्त्वा । ल्यप्) zum Kausativ</li><li>8. Bildung des Infinitivs (तुमुन्) zum Kausativ</li><li>9. Die 10. Präsensklasse (चुरादि = चुर् u.s.w.)</li><li>10. Wortliste</li><li>11. Übung</li></ul><h2 id="lektion-29" tabindex="-1"><a href="./lektion29">Lektion 29</a> <a class="header-anchor" href="#lektion-29" aria-label="Permalink to &quot;[Lektion 29](lektion29)&quot;">​</a></h2><ul><li>1. Verwendung des Parasmaipada und Ātmanepada im Kausativum</li><li>2. Wortliste</li><li>3. Übersetzungsübung zur Wiederholung</li><li>4. Futur und Kausativ zu den bisher gelernten Wurzeln</li></ul><h2 id="lektion-30" tabindex="-1"><a href="./lektion30">Lektion 30</a> <a class="header-anchor" href="#lektion-30" aria-label="Permalink to &quot;[Lektion 30](lektion30)&quot;">​</a></h2><ul><li>1. Die 9. Präsensklasse (क्र्यादि = &quot;क्री u.s.w.&quot;)</li><li>2. Gebrauch des Optativ (लिङ्)</li><li>3. Sekundärendungen der 3. Personen Singular und Plural</li><li>4. Bildung des Optativ Präsens (लिङ्) <ul><li>4.1. Thematische Präsensklassen</li><li>4.2. Athematische Präsensklassen</li></ul></li><li>5. Sandhi von auslautendem -r</li><li>6. Wortliste</li><li>7. Übung</li><li>8. Wiederholungsübung zur Formenlehre</li></ul><h2 id="lektion-31" tabindex="-1"><a href="./lektion31">Lektion 31</a> <a class="header-anchor" href="#lektion-31" aria-label="Permalink to &quot;[Lektion 31](lektion31)&quot;">​</a></h2><ul><li>1. Die 7. Präsensklasse (रुधादि = &quot;रुध् u.s.w.&quot;)</li><li>2. Wortliste</li><li>3. Übung</li></ul><h2 id="lektion-32" tabindex="-1"><a href="./lektion32">Lektion 32</a> <a class="header-anchor" href="#lektion-32" aria-label="Permalink to &quot;[Lektion 32](lektion32)&quot;">​</a></h2><ul><li>1. Die Vergangenheitstempora</li><li>2. Das Imperfekt (लङ्)</li><li>3. Regeln für das Augment</li><li>4. Beispiele für die Imperfektbildung der einzelnen Präsensklassen <ul><li>4.1. Thematische Präsensklassen</li><li>4.2. Athematische Präsensklassen</li></ul></li><li>5. Wortliste</li><li>6. Übung</li><li>7. Übung zur Wiederholung über die Weihnachtsferien</li></ul><h2 id="lektion-33" tabindex="-1"><a href="./lektion33">Lektion 33</a> <a class="header-anchor" href="#lektion-33" aria-label="Permalink to &quot;[Lektion 33](lektion33)&quot;">​</a></h2><ul><li>1. Die Reduplikation (अभ्यास m.) <ul><li>1.1. Der Reduplikationskonsonant</li></ul></li><li>2. Die dritte Präsensklasse (जुहोत्यादि = &quot;जुहोति u.s.w.&quot;) <ul><li>2.1. Der Reduplikationsvokal der 3. Präsensklasse</li></ul></li><li>3. Zum Ablaut von ā</li><li>4. Wurzeln auf -ā der dritten Präsensklasse <ul><li>4.1. Die Wurzeln दा und धा</li></ul></li><li>5. Das Partizip Präsens Parasmaipada der Wurzeln der 3. Präsensklasse</li><li>6. Wortliste</li><li>7. Übung</li></ul><h2 id="lektion-34" tabindex="-1"><a href="./lektion34">Lektion 34</a> <a class="header-anchor" href="#lektion-34" aria-label="Permalink to &quot;[Lektion 34](lektion34)&quot;">​</a></h2><ul><li>1. Das Perfekt (लिट्)</li><li>2. Das reduplizierte Perfekt (द्वित्वलिट्) <ul><li>2.1. Stammabstufung</li><li>2.2. Die Perfektendungen</li><li>2.3. Bindevokal -i-</li><li>2.4. Reduplikation konsonantisch anlautender Wurzeln</li><li>2.5. Reduplikation vokalisch anlautender Wurzeln</li></ul></li><li>3. Typen des reduplizierten Perfekts</li><li>4. Perfekt Typ I: Perfekt ohne Stammabstufung</li><li>5. Perfekt II: starker Stamm Hochstufe, schwacher Stamm Tiefstufe</li><li>6. Wortliste</li><li>7. Übung</li><li>8. Übersetzungsübung</li></ul><h2 id="lektion-35" tabindex="-1"><a href="./lektion35">Lektion 35</a> <a class="header-anchor" href="#lektion-35" aria-label="Permalink to &quot;[Lektion 35](lektion35)&quot;">​</a></h2><ul><li>1. Perfekt Typ III: Starker Stamm Hochstufe/Dehnstufe <ul><li>1.1. Perfekt Typ IIIa: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe</li><li>1.2. Perfekt Typ IIIb: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe</li></ul></li><li>2. Perfekt Typ IV: Wurzeln auf -ā / -ai</li><li>3. Perfekt Typ V: Wurzeln Konsonant-a-Konsonant <ul><li>3.1. Perfekt Typ Va: schwacher Stamm Tiefstufe</li><li>3.2. Perfekt Typ Vb: Wurzeln Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h. Schwacher Stamm ohne Reduplikation, mit -e-</li><li>3.3. Perfekt Typ Vc: Wurzeln Konsonant-a-Konsonant. Schwacher Stamm Hochstufe</li></ul></li><li>4. Wortliste</li><li>5. Übung</li></ul><h2 id="lektion-36" tabindex="-1"><a href="./lektion36">Lektion 36</a> <a class="header-anchor" href="#lektion-36" aria-label="Permalink to &quot;[Lektion 36](lektion36)&quot;">​</a></h2><ul><li>1. Besondere Bildungen des Perfekts</li><li>2. Das periphrastische Perfekt (अनुप्रयोगलिट्)</li><li>3. Perfekt Passiv</li><li>4. Wortliste</li><li>5. Übung</li><li>6. Das Perfekt (लिट्) zu den bisher gelernten Wurzeln</li><li>7. Übersetzungsübung</li><li>8. Wiederholungsübung zur Formenlehre</li></ul><h2 id="lektion-37" tabindex="-1"><a href="./lektion37">Lektion 37</a> <a class="header-anchor" href="#lektion-37" aria-label="Permalink to &quot;[Lektion 37](lektion37)&quot;">​</a></h2><ul><li>1. Das Adverb (क्रियाविशेषनम्)</li><li>2. Adverbialer Gebrauch von Kasusformen <ul><li>2.1. Akkusativ (द्वितीया)</li><li>2.2. Instrumentalis (तृतीया)</li><li>2.3. Dativ (चतुर्थी)</li><li>2.4. Ablativ (पञ्चमी)</li><li>2.5. Genetiv (षष्ठी)</li><li>2.6. Lokativ (सप्तमी)</li></ul></li><li>3. Adverbialer Gebrauch nicht mehr gebräuchlicher Kasusfomen</li><li>4. Bildung von Adverbien mit Adverbialsuffixen</li><li>5. Adverbiale Komposita <ul><li>5.1. Komposita mit einem Adverb oder adverbial gebrauchtem Kasus als Hinterglied</li><li>5.2. Adverbial gebrauchte बहुव्रीहि</li><li>5.3. अव्ययीभाव-Komposita</li></ul></li><li>6. Syntaktisches</li><li>7. Indefinitpronomina</li><li>8. Der Fragesatz <ul><li>8.1. Wortfragen (Ergänzungsfragen)</li><li>8.2. Satzfragen</li></ul></li><li>9. Wortliste</li><li>10. Übung</li><li>11. Wiederholungsübung</li></ul><h2 id="lektion-38" tabindex="-1"><a href="./lektion38">Lektion 38</a> <a class="header-anchor" href="#lektion-38" aria-label="Permalink to &quot;[Lektion 38](lektion38)&quot;">​</a></h2><ul><li>1. Losung der Woche</li><li>2. Lautwandel von Nasalen im Wort</li><li>3. Deklination der Stämme auf -n <ul><li>3.1. Nomina auf -an sowie Nomina -man bzw. -van nach Vokal</li><li>3.2. Nomina auf -man bzw. -van nach Konsonant</li><li>3.3. Maskulina und Neutra auf -in, -min, -vin</li></ul></li><li>4. Zur Nominalbildung: तद्धित-Suffix -in</li><li>5. Syntaktisches zu नामन्</li><li>6. Syntaktisches zu आत्मन्</li><li>7. Konsonantisch auslautende Stämme als Vorderglieder von Komposita</li><li>8. Stämme auf -an als Hinterglied eines बहुव्रीहि</li><li>9. Wortliste</li><li>10. Übung</li><li>11. Wortliste zur Übersetzungsübung</li><li>12. Übersetzungsübung</li></ul><h2 id="lektion-39" tabindex="-1"><a href="./lektion39">Lektion 39</a> <a class="header-anchor" href="#lektion-39" aria-label="Permalink to &quot;[Lektion 39](lektion39)&quot;">​</a></h2><ul><li>1. Die Personalendungen der ersten Person (तृतीयः पुरुषः = &quot;dritte Person&quot;)</li><li>2. Bildung der Verbformen der ersten Person thematischer Präsensstämme <ul><li>2.1. Erste Präsensklasse (भ्वादि)</li><li>2.2. Sechste Präsensklasse (तुदादि)</li><li>2.3. Vierte Präsensklasse (दिवादि)</li><li>2.4. Zehnte Präsensklasse (चुरादि) und Kausative (णिजन्त)</li><li>2.5. Passiv (Suffix यक्)</li></ul></li><li>3. Bildung der Verbformen der ersten Person des einfachen Futur (ऌत्) <ul><li>3.1. अनिट्-Bildung</li><li>3.2. सेट्-Bildung</li></ul></li><li>4. Bildung der Verbformen der ersten Person athematischer Präsensstämme <ul><li>4.1. Zweite Präsensklasse (अदादि)</li><li>4.2. Dritte Präsensklasse (जुहोत्यादि)</li><li>4.3. Fünfte Präsensklasse (स्वादि)</li><li>4.4. Achte Präsensklasse (तनादि)</li><li>4.5. Siebte Präsensklasse (रुधादि)</li><li>4.6. Neunte Präsensklasse (क्र्यादि)</li></ul></li><li>5. Übung</li></ul><h2 id="lektion-40" tabindex="-1"><a href="./lektion40">Lektion 40</a> <a class="header-anchor" href="#lektion-40" aria-label="Permalink to &quot;[Lektion 40](lektion40)&quot;">​</a></h2><ul><li>1. सुभाषितानि</li><li>2. Bildung der Verbformen der ersten Person Perfekt (लिट्) <ul><li>2.1. Perfekt Typ I: keine Stammabstufung</li><li>2.2. Perfekt Typ II: starker Stamm Hochstufe, schwacher Stamm Tiefstufe</li><li>2.3. Perfekt Typ III: Starker Stamm Hochstufe/Dehnstufe <ul><li>2.3.1. Perfekt Typ IIIa: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe</li><li>2.3.2. Perfekt Typ IIIb: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe</li></ul></li><li>2.4. Perfekt Typ IV: Wurzeln auf -ā / -ai</li><li>2.5. Perfekt Typ V: Konsonant-a-Konsonant <ul><li>2.5.1. Perfekt Typ Va: Konsonant-a-Konsonant, schwacher Stamm Tiefstufe</li><li>2.5.2. Perfekt Typ Vb: Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h, Schwacher Stamm ohne Reduplikation, mit -e-</li><li>2.5.3. Perfekt Typ Vc: Konsonant-a-Konsonant, schwacher Stamm Hochstufe</li></ul></li><li>2.6. Besondere Perfekt-Bildungen</li></ul></li><li>3. Bildung der Verbformen der ersten Person des periphrastischen Perfekt (अनुप्रयोगलिट्)</li><li>4. Syntaktisches zur ersten Person (तृतीयः)</li><li>5. Personalpronomen (पुरुषार्थकसर्वनाम) der 1. Person Singular und Plural</li><li>6. Wortliste</li><li>7. Übung</li><li>8. Wiederholungsübung zur Formenlehre</li></ul><h2 id="lektion-41" tabindex="-1"><a href="./lektion41">Lektion 41</a> <a class="header-anchor" href="#lektion-41" aria-label="Permalink to &quot;[Lektion 41](lektion41)&quot;">​</a></h2><ul><li>1. सुभाषिते  (zwei Sprichwörter)</li><li>2. Weitere कृत्-Bildungen auf -a <ul><li>2.1. Partizip Präsens (लडादेशः) Ā, Partizip Präsens (लडादेशः) Passiv, Partizip Futur (ऌडादेशः) Ā <ul><li>2.1.1. Thematische Präsensstämme, Passiv und Futur</li><li>2.1.2. Athematische Präsensklassen</li></ul></li><li>2.2. &quot;Partizip&quot; der passiven Notwendigkeit (Gerundivum) (कृत्य) <ul><li>2.2.1. Das Suffix -तव्य / -तव्या</li><li>2.2.2. Das Suffix -अनीय / -अनीया</li><li>2.2.3. Das Suffix -य / -या</li><li>2.2.4. Das Suffix -त्य / त्या (statt -य / -या)</li></ul></li><li>2.3. Syntaktisches zum &quot;Partizip&quot; der passiven Notwendigkeit (Gerundivum) (कृत्य)</li><li>2.4. Unterschiede im Gebrauch der Gerundiv-Suffixe</li><li>2.5. Keine Verbindung mit सु- und दुस्-</li></ul></li><li>3. Wortliste</li><li>4. Übung</li></ul><h2 id="lektion-42" tabindex="-1"><a href="./lektion42">Lektion 42</a> <a class="header-anchor" href="#lektion-42" aria-label="Permalink to &quot;[Lektion 42](lektion42)&quot;">​</a></h2><ul><li>1. Stämme auf -ṛ <ul><li>1.1. Stämme mit Dehnstufe im starken Stamm</li><li>1.2. Nominalbildung: कृत्-Suffix -तृ</li><li>1.3. Stämme mit Hochstufe im starken Stamm</li><li>1.4. Stämme auf -ṛ in Komposita</li></ul></li><li>2. Wortliste <ul><li>2.1. Einige Verwandtschaftsbezeichnungen</li></ul></li><li>3. Übung</li><li>4. Übersetzungsübung</li></ul><h2 id="lektion-43" tabindex="-1"><a href="./lektion43">Lektion 43</a> <a class="header-anchor" href="#lektion-43" aria-label="Permalink to &quot;[Lektion 43](lektion43)&quot;">​</a></h2><ul><li>1. Personalendungen der 2. Person (मध्यमः = &quot;mittlere &lt;Person&gt;&quot;)</li><li>2. Bildung der Verbalformen der 2. Person (मध्यमः) <ul><li>2.1. Thematische Stämme <ul><li>2.1.1. Erste Präsensklasse (भ्वादि)</li><li>2.1.2. Sechste Präsensklasse (तुदादि)</li><li>2.1.3. Vierte Präsensklasse (दिवादि)</li><li>2.1.4. Zehnte Präsensklasse (चुरादि) und Kausative</li><li>2.1.5. Passiv</li><li>2.1.6. Futur (ऌट्) <ul><li>2.1.6.1. अनिट्-Bildungen</li><li>2.1.6.2. सेट्-Bildungen</li></ul></li></ul></li></ul></li><li>3. Das Personalpronomen der zweiten Person</li><li>4. Wortliste</li><li>5. Übung</li><li>6. संवादः = Gespräch</li></ul><h2 id="lektion-44" tabindex="-1"><a href="./lektion44">Lektion 44</a> <a class="header-anchor" href="#lektion-44" aria-label="Permalink to &quot;[Lektion 44](lektion44)&quot;">​</a></h2><ul><li>1.  Bildung der Verbalformen der 2. Person (मध्यमः) athematischer Stämme mit vokalisch endendem Suffix <ul><li>1.1. Fünfte Präsensklasse (स्वादि)</li><li>1.2. Achte Präsensklasse (तनादि)</li><li>1.3. Neunte Präsensklasse (क्र्यादि)</li></ul></li><li>2. Zum Wortsandhi <ul><li>2.1. Zum Wortsandhi für dh-</li><li>2.2. Zum Wortsandhi für s-</li></ul></li><li>3.  Bildung der Verbalformen der 2. Person (मध्यमः) athematischer Stämme ohne vokalisch endendem Suffix <ul><li>3.1. Zweite Präsensklasse (अदादि)</li></ul></li><li>4. Der Vokativ (आमन्त्रितम्)</li><li>5. Wortliste</li><li>6. Übung</li><li>7. Wiederholungsübung zur Formenlehre</li></ul><h2 id="lektion-45" tabindex="-1"><a href="./lektion45">Lektion 45</a> <a class="header-anchor" href="#lektion-45" aria-label="Permalink to &quot;[Lektion 45](lektion45)&quot;">​</a></h2><ul><li>1. Bildung der Verbalformen der 2. Person (मध्यमः) athematischer Stämme ohne vokalisch endendem Suffix (Fortsetzung) <ul><li>1.1. Dritte Präsensklasse (जुहोत्यादि)</li><li>1.2. Siebte Präsensklasse (रुधादि)</li></ul></li><li>2. Der Vokativ Singular (आमन्त्रितमेकवचने)</li><li>3. Wortliste</li><li>4. Übung</li></ul><h2 id="lektion-46" tabindex="-1"><a href="./lektion46">Lektion 46</a> <a class="header-anchor" href="#lektion-46" aria-label="Permalink to &quot;[Lektion 46](lektion46)&quot;">​</a></h2><ul><li>1. Bildung der Verbalformen der 2. Person (मध्यमः) Perfekt (लिट्) <ul><li>1.1. Endungen</li><li>1.2. Lautveränderung der Endung -dhve</li><li>1.3. Perfekt Typ I: keine Stammabstufung</li><li>1.4. Perfekt Typ II: starker Stamm Hochstufe, schwacher Stamm Tiefstufe</li><li>1.5. Perfekt Typ III: Starker Stamm Hochstufe/Dehnstufe <ul><li>1.5.1. Perfekt Typ IIIa: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe</li><li>1.5.2. Perfekt Typ IIIb: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe</li></ul></li><li>1.6. Perfekt Typ IV: Wurzeln auf -ā / -ai</li><li>1.7. Perfekt Typ V: Konsonant-a-Konsonant <ul><li>1.7.1. Perfekt Typ Va: Konsonant-a-Konsonant, schwacher Stamm Tiefstufe</li><li>1.7.2. Perfekt Typ Vb: Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h, Schwacher Stamm ohne Reduplikation, mit -e-</li><li>1.7.3. Perfekt Typ Vc: Konsonant-a-Konsonant, schwacher Stamm Hochstufe</li></ul></li><li>1.8. Besondere Perfekt-Bildungen</li><li>1.9. Periphrastisches Perfekt (अनुप्रयोगलिट्)</li></ul></li><li>2. Wortliste</li><li>3. Übung</li></ul><h2 id="lektion-47" tabindex="-1"><a href="./lektion47">Lektion 47</a> <a class="header-anchor" href="#lektion-47" aria-label="Permalink to &quot;[Lektion 47](lektion47)&quot;">​</a></h2><ul><li>1. Der Imperativ (लोट्)</li><li>2. Bildung des Imperativs (लोट्) thematischer Präsensstämme <ul><li>2.1. Endungen des Imperativ an thematischen Präsensstämmen</li><li>2.2. Erste Präsensklasse (भ्वादि)</li><li>2.3. Sechste Präsensklasse (तुदादि)</li><li>2.4. Vierte Präsensklasse (दिवादि)</li><li>2.5. Zehnte Präsensklasse (चुरादि) und Kausative</li><li>2.6. Passiv</li></ul></li><li>3. Übung</li></ul><h2 id="lektion-48" tabindex="-1"><a href="./lektion48">Lektion 48</a> <a class="header-anchor" href="#lektion-48" aria-label="Permalink to &quot;[Lektion 48](lektion48)&quot;">​</a></h2><ul><li>1. सुभाषितानि</li><li>2. Bildung des Imperativs (लोट्) athematischer Präsensstämme <ul><li>2.1. Endungen des Imperativ an athematischen Präsensstämmen</li><li>2.2. Form des Präsensstamms</li><li>2.3. Zweite Präsensklasse (अदादि)</li><li>2.4. Dritte Präsensklasse (जुहोत्यादि)</li></ul></li><li>3. Zur Nominalbildung: तद्धित-Suffixe -a und -ya</li><li>4. Wortliste</li><li>5. Übung</li><li>6. Übersetzungsübung</li></ul><h2 id="lektion-49" tabindex="-1"><a href="./lektion49">Lektion 49</a> <a class="header-anchor" href="#lektion-49" aria-label="Permalink to &quot;[Lektion 49](lektion49)&quot;">​</a></h2><ul><li>1. Bildung des Imperativs (लोट्) athematischer Präsensstämme (Fortsetzung) <ul><li>1.1. Siebte Präsensklasse  (रुधादि)</li><li>1.2. Fünfte Präsensklasse (स्वादि)</li><li>1.3. Achte Präsensklasse (तनादि)</li><li>1.4. Neunte Präsensklasse (क्र्यादि)</li></ul></li><li>2. Deklination der Nominalstämme auf -as, -is, -us</li><li>3. Nominalbildung: कृत्-Suffix -as Neutrum</li><li>4. Wortliste</li><li>5. Wiederholungsübung zur Formenlehre</li><li>6. Übersetzungsübung</li></ul><h2 id="lektion-50" tabindex="-1"><a href="./lektion50">Lektion 50</a> <a class="header-anchor" href="#lektion-50" aria-label="Permalink to &quot;[Lektion 50](lektion50)&quot;">​</a></h2><ul><li>1. Nominalbildung: regelmäßige Steigerung</li><li>2. Wortliste</li><li>3. Übersetzungsübung</li></ul><h2 id="lektion-51" tabindex="-1"><a href="./lektion51">Lektion 51</a> <a class="header-anchor" href="#lektion-51" aria-label="Permalink to &quot;[Lektion 51](lektion51)&quot;">​</a></h2><ul><li>1. उपपद-Komposita</li><li>2. Deklination der Stämme, die auf einen einfachen Konsonanten (außer Nasal, Halbvokal, -s) auslauten <ul><li>2.1. Stämme auf nichtpalatalen Verschlusslaut</li><li>2.2. Stämme auf palatalen Verschlusslaut (c, ch, j), ś, ṣ</li><li>2.3. Stämme auf -h</li></ul></li><li>3. Sandhi von anlautendem h-</li><li>4. Sandhi von anlautendem ch-</li><li>5. -ch- im Wortinnern</li><li>6. Wortliste</li><li>7. Übersetzungsübung</li></ul><h2 id="lektion-52" tabindex="-1"><a href="./lektion52">Lektion 52</a> <a class="header-anchor" href="#lektion-52" aria-label="Permalink to &quot;[Lektion 52](lektion52)&quot;">​</a></h2><ul><li>1. Neutrum der Stämme auf -i und -u</li><li>2. Nominalbildung <ul><li>2.1. PPP + -vant: Partizip der Vergangenheit Parasmaipada</li><li>2.2. तद्धित-Suffix -maya / -mayī</li><li>2.3. तद्धित-Suffix -eya</li></ul></li><li>3. Adverbialbildung: Adverbialsuffix -śas</li><li>4. Verbalkomposita, die ausdrücken, dass etwas zu etwas wird oder gemacht wird, was es vorher nicht ist (अभुततद्भावः) <ul><li>4.1. cvi-Bildungen</li><li>4.2. Suffix -sāt</li></ul></li><li>5. Wortwiederholungen (द्विरुक्तम्)</li><li>6. Das Zahlwort (सम्ख्या f.) <ul><li>6.1. Kardinalzahlen <ul><li>6.1.1. Zahladjektive (für 1 bis 19)</li><li>6.1.2. Zahlsubstantive (für 19ff.)</li><li>6.1.3. Syntaktisches zu den Kardinalzahlen</li></ul></li><li>6.2. Ordinalzahlen</li><li>6.3. Zahladverbien</li><li>6.4. Zahladjektive</li><li>6.5. Komposita mit Kardinalzahlen im Vorderglied</li></ul></li><li>7. Wortliste</li><li>8. Übersetzungsübung</li><li>9. Aufgaben während der Semesterferien</li></ul><h2 id="lektion-53-semesterferien" tabindex="-1"><a href="./lektion53">Lektion 53</a>  (Semesterferien) <a class="header-anchor" href="#lektion-53-semesterferien" aria-label="Permalink to &quot;[Lektion 53](lektion53)  (Semesterferien)&quot;">​</a></h2><ul><li>1. Der Dual (द्विवचन n.) der Nomina</li><li>2. Dualendungen des Nomen</li><li>3. Der Dual konsonantisch auslautender Stämme <ul><li>3.1. Stämme ohne Stammabstufung</li><li>3.2. Stämme mit Stammabstufung</li></ul></li><li>4. Der Dual vokalisch auslautender Stämme</li><li>5. Dualdvandva</li><li>6. Der Dual von Pronomina</li><li>7. Pronominaladjektive</li><li>8. Unregelmäßige Steigerung</li><li>9. Deklination der Komparative auf -īyas</li><li>10. Metrik (Lehre von den Versmaßen) <ul><li>10.1. Bedeutung der Bestimmung des Metrums</li><li>10.2. Arten von Metren</li><li>10.3. Die metrische Quantität von Silben</li><li>10.4. Der epische Śloka (श्लोक m.)</li></ul></li><li>11. Übung</li></ul><h2 id="lektion-54" tabindex="-1"><a href="./lektion54">Lektion 54</a> <a class="header-anchor" href="#lektion-54" aria-label="Permalink to &quot;[Lektion 54](lektion54)&quot;">​</a></h2><ul><li>1. Vorbemerkung</li><li>2. Wortbildung: कृत्-Suffix -u an Desiderativstämme</li><li>3. Metrik II: die epische त्रिष्टुभ् und die जगती</li><li>4. Übung zur Metrik</li><li>5. Bildungstypen des Aorist (लुङ्)</li><li>6. Wurzelaorist <ul><li>6.1. Der Aorist der 3.sg.Passiv</li></ul></li><li>7. Übung</li></ul><h2 id="lektion-55" tabindex="-1"><a href="./lektion55">Lektion 55</a> <a class="header-anchor" href="#lektion-55" aria-label="Permalink to &quot;[Lektion 55](lektion55)&quot;">​</a></h2><ul><li>1. Der a-Aorist (Aorist mit Themavokal)</li><li>2. Übung</li></ul><h2 id="lektion-56" tabindex="-1"><a href="./lektion56">Lektion 56</a> <a class="header-anchor" href="#lektion-56" aria-label="Permalink to &quot;[Lektion 56](lektion56)&quot;">​</a></h2><ul><li>1. Der reduplizierte Aorist <ul><li>1.1. Bildung des Aorist der Kausative und der Wurzeln der 10. Präsensklasse</li></ul></li><li>2. Der Injunktiv</li><li>3. Der Verbotssatz</li><li>4. स्म</li><li>5. Übung</li></ul><h2 id="lektion-57" tabindex="-1"><a href="./lektion57">Lektion 57</a> <a class="header-anchor" href="#lektion-57" aria-label="Permalink to &quot;[Lektion 57](lektion57)&quot;">​</a></h2><ul><li>1. Aorist 4: s-Aorist</li><li>2. Übung</li></ul><h2 id="lektion-58" tabindex="-1"><a href="./lektion58">Lektion 58</a> <a class="header-anchor" href="#lektion-58" aria-label="Permalink to &quot;[Lektion 58](lektion58)&quot;">​</a></h2><ul><li>1. Die Primärendungen des Dual (द्विवचनम्)</li><li>2. Der Dual thematischer Präsensklassen: Indikativ Präsens (लट्) <ul><li>2.1. Erste Präsensklasse (भ्वादिगणः)</li><li>2.2. Vierte Präsensklasse (दिवादिगणः)</li><li>2.3. Sechste Präsensklasse (तुदादिगणः)</li><li>2.4. Zehnte Präsensklasse (चुरादिगणः) und Kausative (णिजन्त)</li></ul></li><li>3. Der Dual des einfachen Futurs (ऌत्) <ul><li>3.1. अनिट्</li><li>3.2. सेट्</li></ul></li><li>4. Der Dual Passiv (Suffix -यक्)</li><li>5. Der Dual athematischer Präsensklassen: Indikativ Präsens (लट्) <ul><li>5.1. Zweite Präsensklasse (अदादिगणः)</li><li>5.2. Dritte Präsensklasse (जुहोत्यादिगणः)</li><li>5.3. Fünfte Präsensklasse (स्वादिगणः)</li><li>5.4. Achte Präsensklasse (तनादिगणः)</li><li>5.5. Siebte Präsensklasse (रुधादिगणः)</li><li>5.6. Neunte Präsensklasse (क्र्यादिगणः)</li></ul></li><li>6. Aorist 5: iṣ-Aorist</li><li>7. Übung</li></ul><h2 id="lektion-59" tabindex="-1"><a href="./lektion59">Lektion 59</a> <a class="header-anchor" href="#lektion-59" aria-label="Permalink to &quot;[Lektion 59](lektion59)&quot;">​</a></h2><ul><li>1. Die Sekundärendungen und Imperativendungen des Dual (द्विवचनम्)</li><li>2. Der Dual thematischer Präsensklassen: Optativ (विधिलिङ्), Imperfekt (लङ्), Imperativ (लोट्) <ul><li>2.1. Erste Präsensklasse (भ्वादिगणः)</li><li>2.2. Vierte Präsensklasse (दिवादिगणः)</li><li>2.3. Sechste Präsensklasse (तुदादिगणः)</li><li>2.4. Zehnte Präsensklasse (चुरादिगणः) und Kausative (णिजन्त)</li><li>2.5. Der Passiv (Suffix -यक्)</li></ul></li><li>3. Der Dual athematischer Präsensklassen: Optativ (विधिलिङ्), Imperfekt (लङ्), Imperativ (लोट्) <ul><li>3.1. Zweite Präsensklasse (अदादिगणः)</li><li>3.2. Dritte Präsensklasse (जुहोत्यादिगणः)</li><li>3.3. Fünfte Präsensklasse (स्वादिगणः)</li><li>3.4. Achte Präsensklasse (तनादिगणः)</li><li>3.5. Siebte Präsensklasse (रुधादिगणः)</li><li>3.6. Neunte Präsensklasse (क्र्यादिगणः)</li></ul></li><li>4. Dual (द्विवचनम्) Aorist (लुङ्) <ul><li>4.1. Wurzelaorist</li><li>4.2. a-Aorist</li><li>4.3. Reduplizierter Aorist</li><li>4.4. s-Aorist</li><li>4.5. iṣ-Aorist</li></ul></li><li>5. Aorist (लुङ्) 6: siṣ-Aorist (nur P)</li><li>6. Aorist (लुङ्) 7: sa-Aorist (thematischer s-Aorist)</li><li>7. Übung</li></ul><h2 id="lektion-60" tabindex="-1"><a href="./lektion60">Lektion 60</a> <a class="header-anchor" href="#lektion-60" aria-label="Permalink to &quot;[Lektion 60](lektion60)&quot;">​</a></h2><ul><li>1. Die Perfektendungen des Dual (द्विवचनम्)</li><li>2. Der Dual des reduplizierten Perfekt (द्वित्वलिट्) <ul><li>2.1. Typ 1: keine Stammabstufung</li><li>2.2. Typ 2: starker Stamm Hochstufe, schwacher Stamm Tiefstufe</li><li>2.3. Typ 3: Starker Stamm Hochstufe/Dehnstufe <ul><li>2.3.1. Typ 3a: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe</li><li>2.3.2. Typ 3b: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe</li></ul></li><li>2.4. Typ 4: Wurzeln auf -ā / -ai</li><li>2.5. Typ 5: Konsonant-a-Konsonant <ul><li>2.5.1. Typ 5a: Konsonant-a-Konsonant, schwacher Stamm Tiefstufe</li><li>2.5.2. Typ 5b: Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h, Schwacher Stamm ohne Reduplikation, mit -e-</li><li>2.5.3. Typ 5c: Konsonant-a-Konsonant, schwacher Stamm Hochstufe</li></ul></li></ul></li><li>3. Der Dual des periphrastischen Perfekt (अनुप्रयोगलिट्)</li><li>4. Das Partizip परस्मैपद des reduplizierten Perfekt (द्वित्वलिट्)</li><li>5. Deklination der Stämme auf -añc (-ac) <ul><li>5.1. Dreistämmige Stämme auf -añc</li><li>5.2. Zweistämmige Stämme auf -añc</li></ul></li><li>6. Das Desiderativum (सन्) <ul><li>6.1. Bildung des Desiderativstammes</li><li>6.2. Konjugation des Desiderativs (सन्)</li></ul></li><li>7. Übung</li></ul><h2 id="lektion-61" tabindex="-1"><a href="./lektion61">Lektion 61</a> <a class="header-anchor" href="#lektion-61" aria-label="Permalink to &quot;[Lektion 61](lektion61)&quot;">​</a></h2><ul><li>1. Deklination der Wurzelnomina auf -ā, -ī, -ū <ul><li>1.1. Wurzelnomina auf -ā am Ende von तत्पुरुष</li><li>1.2. Feminine Wurzelnomina auf -ī</li><li>1.3. Wurzelnomina auf -ī am Ende von तत्पुरुष</li><li>1.4. Einsilbige, feminine Wurzelnomina auf -ū</li><li>1.5. Wurzelnomina auf -ū am Ende von तत्पुरुष</li><li>1.6. Deklination mehrsilbiger Feminina auf -ū</li></ul></li><li>2. Das periphrastische Futur (लुट्)</li><li>3. Das Intensivum (Frequentativum) (चर्करीतम्) <ul><li>3.1. Ātmanepada-Intensivum</li><li>3.2. Parasmaipada-Intensivum</li></ul></li><li>4. Denominativa (नामधातु) <ul><li>4.1. Bildung ohne besonderes Suffix, Parasmaipada</li><li>4.2. Bildung mit Suffix -ya, Parasmaipada</li><li>4.3. Bildung mit dem Suffix -kāmya, Parasmaipada</li><li>4.4. Bildung mit dem Suffix -sya oder -asya, Parasmaipada</li><li>4.5. Bildung mit dem Suffix -ya, Ātmanepada</li><li>4.6. Bildung mit dem Suffix -aya, -āpaya</li></ul></li><li>5. Der Benediktiv (आशीर्लिङ्)</li><li>6. Der Konditionalis (ऌङ्)</li><li>7. Deklination der Nomina auf -ai, -o, -au</li><li>8. Restliche Pronomina <ul><li>8.1. Personalpronomen des Dual</li><li>8.2. Demonstrativpronomen अदस् &quot;jener (entfernte)&quot;</li></ul></li><li>9. Entlassung in den Ozean der Sanskritliteratur: ಶ್ರೀಗಣನಾಥ / श्रीगणनाथ</li></ul><p>ENDE DES SANSKRITKURSES</p>',127)])])}const f=e(t,[["render",r]]);export{m as __pageData,f as default};
